import{_ as l,o as i,c as e,ag as o}from"./chunks/framework.CrllrrHC.js";const u=JSON.parse('{"title":"mac软件推荐（Windows 用户转 Mac 必备小工具）","description":"","frontmatter":{"title":"mac软件推荐（Windows 用户转 Mac 必备小工具）","slug":"mac-apps-for-windows-user","date":"2026-05-13T00:00:00.000Z","tags":["Mac","macOS","软件推荐","效率工具","开发工具"]},"headers":[],"relativePath":"column/mac/001_app.md","filePath":"column/mac/001_app.md","lastUpdated":1778642216000}'),r={name:"column/mac/001_app.md"};function p(t,a,h,c,n,d){return i(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="mac-软件推荐-windows-用户转-mac-必备小工具" tabindex="-1">mac 软件推荐（Windows 用户转 Mac 必备小工具） <a class="header-anchor" href="#mac-软件推荐-windows-用户转-mac-必备小工具" aria-label="Permalink to &quot;mac 软件推荐（Windows 用户转 Mac 必备小工具）&quot;">​</a></h1><p>我是一个长期使用 Windows 的用户。</p><p>真正开始接触 Mac，其实是上班之后。</p><p>刚切过来的那段时间，说实话并不适应。</p><p>甚至会有一种：</p><blockquote><p>“这系统怎么什么都不顺手？”</p></blockquote><p>的感觉。</p><p>比如：</p><ul><li>没有右键新建</li><li>鼠标滚轮方向不习惯</li><li>Finder 没资源管理器好用</li><li>软件关闭逻辑奇怪</li><li>多窗口切换不舒服</li><li>软件卸载不干净</li><li>外接鼠标体验一般</li></ul><p>但后来慢慢发现：</p><p>Mac 的问题很多不是系统本身。</p><p>而是：</p><blockquote><p>缺少适合自己的工具链。</p></blockquote><p>装对软件之后，整个体验会舒服非常多。</p><p>所以这篇文章。</p><p>主要整理一些：</p><h1 id="特别适合-windows-用户转-mac-的软件" tabindex="-1">特别适合 Windows 用户转 Mac 的软件 <a class="header-anchor" href="#特别适合-windows-用户转-mac-的软件" aria-label="Permalink to &quot;特别适合 Windows 用户转 Mac 的软件&quot;">​</a></h1><p>尤其适合：</p><ul><li>程序员</li><li>办公党</li><li>学生</li><li>重度电脑用户</li></ul><hr><h1 id="_1-runcat" tabindex="-1">1. RunCat <a class="header-anchor" href="#_1-runcat" aria-label="Permalink to &quot;1. RunCat&quot;">​</a></h1><p>一个非常有意思的小工具。</p><p>它会在状态栏显示一只奔跑的小猫（或者别的动物）。</p><p>CPU 占用越高。</p><p>它跑得越快。</p><hr><h2 id="它有什么用" tabindex="-1">它有什么用？ <a class="header-anchor" href="#它有什么用" aria-label="Permalink to &quot;它有什么用？&quot;">​</a></h2><p>严格来说：</p><blockquote><p>没什么生产力价值。</p></blockquote><p>但它属于：</p><blockquote><p>“会让你心情很好”的软件。</p></blockquote><p>尤其是程序员。</p><p>当你：</p><ul><li>开 Docker</li><li>跑前端项目</li><li>IDEA 索引</li><li>编译项目</li><li>Chrome 开几十个标签页</li></ul><p>的时候。</p><p>你会非常直观看到：</p><blockquote><p>“哦，CPU 炸了。”</p></blockquote><hr><h2 id="适合人群" tabindex="-1">适合人群 <a class="header-anchor" href="#适合人群" aria-label="Permalink to &quot;适合人群&quot;">​</a></h2><ul><li>程序员</li><li>喜欢桌面小组件的人</li><li>想实时观察 CPU 状态的人</li></ul><hr><h1 id="_2-右键助手-rightmenu-master" tabindex="-1">2. 右键助手（RightMenu Master） <a class="header-anchor" href="#_2-右键助手-rightmenu-master" aria-label="Permalink to &quot;2. 右键助手（RightMenu Master）&quot;">​</a></h1><p>Windows 用户刚切到 Mac 时。</p><p>最难受的一件事：</p><h1 id="finder-右键功能太少。" tabindex="-1">Finder 右键功能太少。 <a class="header-anchor" href="#finder-右键功能太少。" aria-label="Permalink to &quot;Finder 右键功能太少。&quot;">​</a></h1><p>很多 Windows 上习惯的操作。</p><p>Mac 原生都没有。</p><p>比如：</p><ul><li>新建 txt 文件</li><li>剪切</li><li>复制路径</li><li>终端打开</li><li>压缩解压</li><li>快速创建文件</li></ul><p>而 <code>RightMenu Master</code> 基本能补齐这些体验。</p><hr><h2 id="为什么推荐" tabindex="-1">为什么推荐？ <a class="header-anchor" href="#为什么推荐" aria-label="Permalink to &quot;为什么推荐？&quot;">​</a></h2><p>因为它会让 Finder 更像：</p><blockquote><p>“正常的 Windows 文件管理器”。</p></blockquote><p>属于：</p><h1 id="windows-用户幸福感提升特别明显的软件。" tabindex="-1">Windows 用户幸福感提升特别明显的软件。 <a class="header-anchor" href="#windows-用户幸福感提升特别明显的软件。" aria-label="Permalink to &quot;Windows 用户幸福感提升特别明显的软件。&quot;">​</a></h1><hr><h1 id="_3-bettermouse" tabindex="-1">3. BetterMouse <a class="header-anchor" href="#_3-bettermouse" aria-label="Permalink to &quot;3. BetterMouse&quot;">​</a></h1><p>Mac 原生对第三方鼠标支持真的一般。</p><p>尤其是：</p><ul><li>罗技</li><li>雷蛇</li><li>英菲克</li><li>ATK</li><li>国产电竞鼠标</li></ul><p>很多时候都会出现：</p><ul><li>鼠标加速度奇怪</li><li>滚轮方向别扭</li><li>滚动不顺滑</li><li>回报率异常</li><li>自定义按键失效</li></ul><p>的问题。</p><p>而 <code>BetterMouse</code> 基本能解决大部分问题。</p><hr><h2 id="我最喜欢的功能" tabindex="-1">我最喜欢的功能 <a class="header-anchor" href="#我最喜欢的功能" aria-label="Permalink to &quot;我最喜欢的功能&quot;">​</a></h2><h3 id="_1-鼠标独立配置" tabindex="-1">1. 鼠标独立配置 <a class="header-anchor" href="#_1-鼠标独立配置" aria-label="Permalink to &quot;1. 鼠标独立配置&quot;">​</a></h3><p>不同鼠标可以：</p><ul><li>单独 DPI</li><li>单独滚动速度</li><li>单独按键</li><li>单独滚轮方向</li></ul><p>这个真的很舒服。</p><hr><h3 id="_2-平滑滚动" tabindex="-1">2. 平滑滚动 <a class="header-anchor" href="#_2-平滑滚动" aria-label="Permalink to &quot;2. 平滑滚动&quot;">​</a></h3><p>很多鼠标在 Mac 上滚动时。</p><p>会有一种：</p><blockquote><p>“一格一格卡着滚”</p></blockquote><p>的感觉。</p><p>BetterMouse 调完之后会顺滑很多。</p><p>体验提升非常明显。</p><hr><h1 id="_4-dockdoor" tabindex="-1">4. DockDoor <a class="header-anchor" href="#_4-dockdoor" aria-label="Permalink to &quot;4. DockDoor&quot;">​</a></h1><p>这是我觉得：</p><h1 id="windows-用户转-mac-必装的软件之一。" tabindex="-1">Windows 用户转 Mac 必装的软件之一。 <a class="header-anchor" href="#windows-用户转-mac-必装的软件之一。" aria-label="Permalink to &quot;Windows 用户转 Mac 必装的软件之一。&quot;">​</a></h1><p>它主要是：</p><blockquote><p>给 Mac 补全类似 Windows 的窗口预览体验。</p></blockquote><hr><h2 id="为什么会需要它" tabindex="-1">为什么会需要它？ <a class="header-anchor" href="#为什么会需要它" aria-label="Permalink to &quot;为什么会需要它？&quot;">​</a></h2><p>如果你长期用 Windows。</p><p>应该很熟悉：</p><ul><li>鼠标移动到任务栏图标</li><li>自动显示窗口预览</li><li>快速切换窗口</li></ul><p>但 Mac 原生其实没有这种体验。</p><p>Dock 只能看到：</p><blockquote><p>“应用”。</p></blockquote><p>而不是：</p><blockquote><p>“窗口”。</p></blockquote><p>这对于刚从 Windows 转过来的人来说。</p><p>其实很不习惯。</p><hr><h2 id="它最舒服的功能" tabindex="-1">它最舒服的功能 <a class="header-anchor" href="#它最舒服的功能" aria-label="Permalink to &quot;它最舒服的功能&quot;">​</a></h2><h3 id="_1-dock-窗口预览" tabindex="-1">1. Dock 窗口预览 <a class="header-anchor" href="#_1-dock-窗口预览" aria-label="Permalink to &quot;1. Dock 窗口预览&quot;">​</a></h3><p>鼠标移动到 Dock 图标时。</p><p>会显示当前窗口缩略图。</p><p>特别适合：</p><ul><li>多个 Finder</li><li>多个 Chrome</li><li>多个 IDEA 项目</li><li>多终端窗口</li></ul><p>的人。</p><hr><h3 id="_2-更好的窗口切换逻辑" tabindex="-1">2. 更好的窗口切换逻辑 <a class="header-anchor" href="#_2-更好的窗口切换逻辑" aria-label="Permalink to &quot;2. 更好的窗口切换逻辑&quot;">​</a></h3><p>Mac 原生：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Command + Tab</span></span></code></pre></div><p>很多时候切的是：</p><blockquote><p>应用</p></blockquote><p>不是：</p><blockquote><p>窗口。</p></blockquote><p>而 DockDoor 会更接近 Windows 的逻辑。</p><p>多窗口切换会舒服很多。</p><hr><h2 id="我的实际感受" tabindex="-1">我的实际感受 <a class="header-anchor" href="#我的实际感受" aria-label="Permalink to &quot;我的实际感受&quot;">​</a></h2><p>刚开始用 Mac 时。</p><p>我最不适应的就是：</p><h1 id="多窗口管理。" tabindex="-1">多窗口管理。 <a class="header-anchor" href="#多窗口管理。" aria-label="Permalink to &quot;多窗口管理。&quot;">​</a></h1><p>后来装了 DockDoor 之后。</p><p>整体会更像：</p><blockquote><p>“Windows + Mac 的混合体验”。</p></blockquote><p>舒服非常多。</p><hr><h1 id="_5-slidepad" tabindex="-1">5. Slidepad <a class="header-anchor" href="#_5-slidepad" aria-label="Permalink to &quot;5. Slidepad&quot;">​</a></h1><p>这是我目前最喜欢的 Mac 软件之一。</p><p>简单来说：</p><blockquote><p>“侧边栏版浏览器”。</p></blockquote><hr><h2 id="它能干什么" tabindex="-1">它能干什么？ <a class="header-anchor" href="#它能干什么" aria-label="Permalink to &quot;它能干什么？&quot;">​</a></h2><p>你可以把网页收进侧边栏。</p><p>比如：</p><ul><li>ChatGPT</li><li>飞书</li><li>微信读书</li><li>GitHub</li><li>翻译网站</li><li>Notion</li></ul><p>然后随时从侧边滑出来。</p><hr><h2 id="为什么特别好用" tabindex="-1">为什么特别好用？ <a class="header-anchor" href="#为什么特别好用" aria-label="Permalink to &quot;为什么特别好用？&quot;">​</a></h2><p>对于开发来说。</p><p>经常会：</p><ul><li>一边写代码</li><li>一边查文档</li><li>一边看 AI</li><li>一边查 GitHub</li></ul><p>如果全放浏览器。</p><p>标签页很容易爆炸。</p><p>而 Slidepad 会把这些：</p><blockquote><p>“高频工具网页”</p></blockquote><p>统一收纳起来。</p><hr><h2 id="特别适合" tabindex="-1">特别适合 <a class="header-anchor" href="#特别适合" aria-label="Permalink to &quot;特别适合&quot;">​</a></h2><ul><li>小屏幕 MacBook</li><li>多任务办公</li><li>写代码查资料</li><li>AI 重度用户</li></ul><hr><h1 id="_6-appcleaner-uninstaller" tabindex="-1">6. AppCleaner &amp; Uninstaller <a class="header-anchor" href="#_6-appcleaner-uninstaller" aria-label="Permalink to &quot;6. AppCleaner &amp; Uninstaller&quot;">​</a></h1><p>Mac 卸载软件其实并不干净。</p><p>很多软件即使拖进垃圾桶。</p><p>它的：</p><ul><li>配置文件</li><li>缓存</li><li>日志</li><li>启动项</li></ul><p>依然还在。</p><p>久了之后系统会越来越乱。</p><hr><h2 id="appcleaner-的作用" tabindex="-1">AppCleaner 的作用 <a class="header-anchor" href="#appcleaner-的作用" aria-label="Permalink to &quot;AppCleaner 的作用&quot;">​</a></h2><p>它会自动扫描：</p><ul><li>软件残留</li><li>配置文件</li><li>缓存文件</li></ul><p>然后一起删除。</p><hr><h2 id="为什么推荐-1" tabindex="-1">为什么推荐？ <a class="header-anchor" href="#为什么推荐-1" aria-label="Permalink to &quot;为什么推荐？&quot;">​</a></h2><p>因为很多 Windows 用户以为：</p><blockquote><p>Mac 拖进垃圾桶 = 卸载。</p></blockquote><p>实际上并不是。</p><p>所以这个工具我觉得属于：</p><h1 id="mac-必备软件。" tabindex="-1">Mac 必备软件。 <a class="header-anchor" href="#mac-必备软件。" aria-label="Permalink to &quot;Mac 必备软件。&quot;">​</a></h1><hr><h1 id="_7-wailbrew" tabindex="-1">7. WailBrew <a class="header-anchor" href="#_7-wailbrew" aria-label="Permalink to &quot;7. WailBrew&quot;">​</a></h1><p>如果你刚从 Windows 转过来。</p><p>那你大概率会经历：</p><h1 id="mac-到底怎么装开发环境" tabindex="-1">“Mac 到底怎么装开发环境？” <a class="header-anchor" href="#mac-到底怎么装开发环境" aria-label="Permalink to &quot;“Mac 到底怎么装开发环境？”&quot;">​</a></h1><p>这个阶段。</p><p>而在 Mac 的开发生态里。</p><h1 id="homebrew-基本是核心。" tabindex="-1">Homebrew 基本是核心。 <a class="header-anchor" href="#homebrew-基本是核心。" aria-label="Permalink to &quot;Homebrew 基本是核心。&quot;">​</a></h1><hr><h2 id="homebrew-是什么" tabindex="-1">Homebrew 是什么？ <a class="header-anchor" href="#homebrew-是什么" aria-label="Permalink to &quot;Homebrew 是什么？&quot;">​</a></h2><p>可以理解成：</p><blockquote><p>Mac 的包管理器。</p></blockquote><p>类似：</p><ul><li>apt</li><li>yum</li><li>scoop</li><li>winget</li></ul><hr><h2 id="为什么推荐-wailbrew" tabindex="-1">为什么推荐 WailBrew？ <a class="header-anchor" href="#为什么推荐-wailbrew" aria-label="Permalink to &quot;为什么推荐 WailBrew？&quot;">​</a></h2><p>因为很多新手刚接触：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xxx</span></span></code></pre></div><p>会有点懵。</p><p>而 <code>WailBrew</code> 提供了图形化界面。</p><p>你可以：</p><ul><li>搜索软件</li><li>安装 brew 包</li><li>更新软件</li><li>管理环境</li></ul><p>对于新手特别友好。</p><hr><h1 id="_8-scherlock" tabindex="-1">8. Scherlock <a class="header-anchor" href="#_8-scherlock" aria-label="Permalink to &quot;8. Scherlock&quot;">​</a></h1><p>这是一个我非常推荐的：</p><h1 id="mac-文件检索工具。" tabindex="-1">Mac 文件检索工具。 <a class="header-anchor" href="#mac-文件检索工具。" aria-label="Permalink to &quot;Mac 文件检索工具。&quot;">​</a></h1><p>尤其适合：</p><ul><li>文件很多的人</li><li>经常找资料的人</li><li>程序员</li><li>Windows 转 Mac 用户</li></ul><hr><h2 id="为什么需要它" tabindex="-1">为什么需要它？ <a class="header-anchor" href="#为什么需要它" aria-label="Permalink to &quot;为什么需要它？&quot;">​</a></h2><p>Mac 原生 Spotlight 虽然很好用。</p><p>但有时候：</p><ul><li>搜索速度一般</li><li>文件筛选不够直观</li><li>搜代码不方便</li><li>中文搜索体验一般</li><li>大量文件时不够精准</li></ul><p>而 <code>Scherlock</code> 会更像：</p><blockquote><p>“增强版 Everything”。</p></blockquote><hr><h2 id="windows-用户应该很熟悉" tabindex="-1">Windows 用户应该很熟悉 <a class="header-anchor" href="#windows-用户应该很熟悉" aria-label="Permalink to &quot;Windows 用户应该很熟悉&quot;">​</a></h2><p>如果你以前是 Windows 用户。</p><p>那大概率知道：</p><h1 id="everything" tabindex="-1">Everything <a class="header-anchor" href="#everything" aria-label="Permalink to &quot;Everything&quot;">​</a></h1><p>那个几乎秒搜文件的软件。</p><p>而 Scherlock 在 Mac 上。</p><p>会有一种类似的感觉。</p><hr><h2 id="我最喜欢的地方" tabindex="-1">我最喜欢的地方 <a class="header-anchor" href="#我最喜欢的地方" aria-label="Permalink to &quot;我最喜欢的地方&quot;">​</a></h2><h3 id="_1-搜索速度非常快" tabindex="-1">1. 搜索速度非常快 <a class="header-anchor" href="#_1-搜索速度非常快" aria-label="Permalink to &quot;1. 搜索速度非常快&quot;">​</a></h3><p>输入关键字。</p><p>基本瞬间就能出结果。</p><p>特别适合：</p><ul><li>下载目录</li><li>项目文件</li><li>图片素材</li><li>文档资料</li></ul><p>很多的人。</p><hr><h3 id="_2-更细的文件筛选" tabindex="-1">2. 更细的文件筛选 <a class="header-anchor" href="#_2-更细的文件筛选" aria-label="Permalink to &quot;2. 更细的文件筛选&quot;">​</a></h3><p>支持：</p><ul><li>文件类型</li><li>文件时间</li><li>文件大小</li><li>文件路径</li></ul><p>查东西效率会高很多。</p><hr><h3 id="_3-对程序员特别友好" tabindex="-1">3. 对程序员特别友好 <a class="header-anchor" href="#_3-对程序员特别友好" aria-label="Permalink to &quot;3. 对程序员特别友好&quot;">​</a></h3><p>经常会遇到：</p><ul><li>忘记项目在哪</li><li>忘记配置文件名字</li><li>找不到 sql 文件</li><li>找不到下载内容</li></ul><p>这种情况。</p><p>有了 Scherlock。</p><p>直接搜关键字就行。</p><hr><h1 id="mac-和-windows-的差异感受" tabindex="-1">Mac 和 Windows 的差异感受 <a class="header-anchor" href="#mac-和-windows-的差异感受" aria-label="Permalink to &quot;Mac 和 Windows 的差异感受&quot;">​</a></h1><p>刚开始接触 Mac 的时候。</p><p>我其实非常不适应。</p><p>尤其是：</p><ul><li>Finder</li><li>多窗口逻辑</li><li>快捷键</li><li>鼠标操作</li><li>软件关闭逻辑</li></ul><p>都会让 Windows 用户很难受。</p><hr><h2 id="但用久之后会发现" tabindex="-1">但用久之后会发现 <a class="header-anchor" href="#但用久之后会发现" aria-label="Permalink to &quot;但用久之后会发现&quot;">​</a></h2><p>Mac 更像：</p><blockquote><p>“一个偏向工作流和专注的系统”。</p></blockquote><p>尤其是：</p><ul><li>多桌面</li><li>触控板</li><li>动画一致性</li><li>Unix 生态</li><li>开发环境</li></ul><p>这些地方。</p><p>确实会越用越舒服。</p><hr><h2 id="当然" tabindex="-1">当然 <a class="header-anchor" href="#当然" aria-label="Permalink to &quot;当然&quot;">​</a></h2><p>Windows 依然是：</p><h1 id="游戏和兼容性最强的平台。" tabindex="-1">游戏和兼容性最强的平台。 <a class="header-anchor" href="#游戏和兼容性最强的平台。" aria-label="Permalink to &quot;游戏和兼容性最强的平台。&quot;">​</a></h1><p>所以我现在基本属于：</p><ul><li>游戏娱乐用 Windows</li><li>开发办公用 Mac</li></ul><p>的状态。</p><hr><h1 id="最后推荐几个我觉得-mac-必学的东西" tabindex="-1">最后推荐几个我觉得 Mac 必学的东西 <a class="header-anchor" href="#最后推荐几个我觉得-mac-必学的东西" aria-label="Permalink to &quot;最后推荐几个我觉得 Mac 必学的东西&quot;">​</a></h1><h2 id="_1-homebrew" tabindex="-1">1. Homebrew <a class="header-anchor" href="#_1-homebrew" aria-label="Permalink to &quot;1. Homebrew&quot;">​</a></h2><p>Mac 的核心包管理器。</p><p>很多开发环境：</p><ul><li>node</li><li>git</li><li>python</li><li>docker</li><li>mysql</li></ul><p>都会用它安装。</p><p>属于：</p><h1 id="学-mac-基本绕不过去的东西。" tabindex="-1">学 Mac 基本绕不过去的东西。 <a class="header-anchor" href="#学-mac-基本绕不过去的东西。" aria-label="Permalink to &quot;学 Mac 基本绕不过去的东西。&quot;">​</a></h1><hr><h2 id="_2-raycast" tabindex="-1">2. Raycast <a class="header-anchor" href="#_2-raycast" aria-label="Permalink to &quot;2. Raycast&quot;">​</a></h2><p>Mac 神器。</p><p>可以理解成：</p><blockquote><p>超级增强版 Spotlight。</p></blockquote><hr><h2 id="它能干什么-1" tabindex="-1">它能干什么？ <a class="header-anchor" href="#它能干什么-1" aria-label="Permalink to &quot;它能干什么？&quot;">​</a></h2><ul><li>搜文件</li><li>启动软件</li><li>AI</li><li>剪贴板历史</li><li>快捷命令</li><li>窗口管理</li><li>脚本自动化</li></ul><p>很多人用了之后。</p><p>甚至开始：</p><blockquote><p>“尽量不用鼠标”。</p></blockquote><hr><h2 id="_3-rectangle" tabindex="-1">3. Rectangle <a class="header-anchor" href="#_3-rectangle" aria-label="Permalink to &quot;3. Rectangle&quot;">​</a></h2><p>免费的窗口管理工具。</p><p>让 Mac 拥有类似 Windows 的：</p><ul><li>左右分屏</li><li>快捷贴边</li><li>最大化</li></ul><p>体验。</p><p>属于：</p><h1 id="windows-用户过渡神器。" tabindex="-1">Windows 用户过渡神器。 <a class="header-anchor" href="#windows-用户过渡神器。" aria-label="Permalink to &quot;Windows 用户过渡神器。&quot;">​</a></h1><hr><h1 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h1><p>如果你也是：</p><h1 id="从-windows-转到-mac-的用户。" tabindex="-1">从 Windows 转到 Mac 的用户。 <a class="header-anchor" href="#从-windows-转到-mac-的用户。" aria-label="Permalink to &quot;从 Windows 转到 Mac 的用户。&quot;">​</a></h1><p>那我非常建议优先解决：</p><ul><li>鼠标体验</li><li>Finder 操作</li><li>窗口管理</li><li>软件卸载</li><li>开发环境</li></ul><p>这些问题。</p><p>因为只要这些舒服了。</p><p>Mac 的体验会直接提升一个档次。</p><p>很多人不是不适应 Mac。</p><p>而是：</p><blockquote><p>没装对工具。</p></blockquote>',294)])])}const b=l(r,[["render",p]]);export{u as __pageData,b as default};
